INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (2, 'instagram', '2026-06-29', 'Reel', 'Reel 4: Papaya Myth

Ref link: 

HOOK
"Papaya causes miscarriage — you must have heard that, right? Let''s talk about whether that''s actually true."

You heard me right — this myth has some truth to it, but it''s not the full picture, and the details matter.

Unripe and semi-ripe papaya contain high levels of latex and an enzyme called papain. Papain — that''s the compound that can trigger uterine contractions when consumed in large amounts. This is why unripe papaya has traditionally been avoided during pregnancy.

Ripe papaya, on the other hand, has much lower levels of this compound. In small to moderate amounts, it''s generally considered safe and is actually a good source of fibre, vitamin C, and folate — all useful in pregnancy.

But — and this is the part that gets missed — "safe" doesn''t mean "no risk in any amount." Number one, moderation matters. A small bowl occasionally is very different from eating it daily in large quantities. Number two, if you have a history of miscarriage, threatened miscarriage, or your pregnancy is considered high-risk, even ripe papaya is best avoided unless your doctor clears it.

I do not support blanket statements like "ripe papaya is completely safe for everyone" — because pregnancy isn''t one-size-fits-all, and your specific history changes the answer.

This is a common question, and a fair one to ask. If you''re unsure, just bring it up at your next visit — it takes thirty seconds to clear up, and it''s worth it.

---

VISUAL NOTES:
Split-screen or side-by-side of unripe vs ripe papaya as each is discussed. On-screen text highlighting "papain" with simple definition overlay. Doctor to camera for the moderation/high-risk point — this is the section that needs the most weight.', 'Pending', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'No', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (2, 'instagram', '2026-07-01', 'Reel', 'Reel 5: Do not have kids


Ref link:

https://www.instagram.com/reel/DSuhlxuj-Tb/?igsh=dWpxN3lteXBnbHAw


HOOK
"Do not have kids — you heard me right, do not — until you''ve checked these three things first."

Number one — your partner''s fertility evaluation. This cannot be a one-sided conversation. Fertility issues affect men and women almost equally, and a basic semen analysis is a simple test that tells you a lot early on. Skipping this isn''t caution, it''s just delaying information you''ll need eventually anyway.

Number two — financial readiness. I''m not talking about being rich. I''m talking about having clarity — maternity leave, medical costs, the actual day-to-day cost of raising a child in your city. Money stress during pregnancy and after birth is real, and planning for it ahead of time changes how you experience the entire journey.

Number three — emotional readiness, and this one gets skipped the most. Are you and your partner aligned on parenting values, support systems, how you''ll handle the sleepless nights and the mental load? This is very common to overlook, and very manageable once you actually talk about it — but only if the conversation happens before, not during.

I do not support the idea that "it''ll just work itself out." Some things will. These three won''t — not without a plan.

This is very common — most couples haven''t had all three conversations before they start trying. And that''s completely fixable. If you want to start with the fertility evaluation piece, that''s something we can do together at Janya, right here in HSR Layout.

---

VISUAL NOTES:
On-screen text for "1," "2," "3" as each is introduced. Tone shifts slightly warmer on point 3 (emotional readiness) — visually this could be a softer lighting or closer framing to mark the shift from practical to personal. End on clinic exterior or a warm, hopeful visual rather than clinical.', 'Pending', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'No', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'migration');
