INSERT INTO marketing_content_tracker (client_id, platform, date, post_type, script, status, link, time, caption, views, likes, comments, shares, saves, follows, avg_watch_time_pct, boosted, engagement_rate_pct, save_rate_pct, content_score, youtube_views, youtube_watch_time, youtube_avg_view_duration, youtube_ctr, source) VALUES (2, 'instagram', '2026-07-08', 'Reel', 'Reel 7 : Addressing the fear of being judged


Ashu : "...and it''s been happening for a few months now, and I just— I don''t know if ."Che... and she''s telling me this like it''s normal?"

"This is what you think happens when you tell your gynaecologist what''s actually been going on."

"...Yeah. That''s the version that''s been living in your head this whole time. But here''s what''s actually going on. It''s not an exam. It''s not even the symptoms. It''s that moment right before — where you''re mentally preparing to explain or apologize for something about your own body."

"Maybe it''s something about hygiene, or your weight, or hair, or a past relationship, or just... how long it''s been since your last visit. And yeah — I get why it feels huge to you. But a gynaecologist sees that exact thing, whatever yours is, multiple times, every single day. Not as a judgment. As a pattern. The thing you''ve built into this whole identity crisis in your head? To them, it''s Tuesday."

"So the version of you that''s been avoiding this? She''s not actually avoiding the doctor. She''s avoiding a version of judgment that was never in the room to begin with. The real room just has a doctor who''s seen it before, didn''t blink, and is there to help you feel better."

"The appointment you''ve been dreading? It''s smaller. Like, a lot smaller than the one in your head."

"If there''s something specific that''s been making you put this off — tell me in the comments. I promise it''s not as unusual as you think."
